INSERT INTO `blogs` VALUES ('3','1','209','2006-09-27 19:28:00','2','MCS 1.58 angefangen','1','<p>Wie bei jeder neuen Version fallen Fehler auf.<br /><br />\nSo auch bei dieser Version.<br /><br />\nNun Ideen sind auch neue dazugekommen und ich denke mir fällt auch noch was ein.</p><br />\n<p><strong>Todolist:</strong><br />\n<a href=\"index.php?page=infos&amp;action=details&amp;id=24\">Hier</a></p><br />\n<p><strong>Buglist:</strong></p><br />\n&lt;ul&gt;<br />\n &lt;li&gt;<br />\n     Beim Hochladen von Dateien kann es bei Doppelklick zu Fehlern kommen. &lt;blockquote&gt;<br />\n       Edit: lag am FILE SIZE Limit<br />\n    &lt;/blockquote&gt;<br />\n&lt;/li&gt;<br />\n &lt;li&gt;<br />\n     Date funktion Funktioniert manchmal nicht, d.h. Datum wird nicht eingestellt obwohl es eine Datumsspalte gibt. &lt;blockquote&gt;<br />\n       Edit:Bug gefunden lag am mangelndem Update in der Preview Funktion<br />\n    &lt;/blockquote&gt;<br />\n  &lt;/li&gt;<br />\n&lt;/ul&gt;<br />\n','<p>Wie bei jeder neuen Version fallen Fehler auf.<br /><br />\nSo auch bei dieser Version.<br /><br />\nNun Ideen sind auch neue dazugekommen und ich denke mir fällt auch noch was ein.</p><br />\n<p><strong>Todolist:</strong><br />\n<a href=\"index.php?page=infos&amp;action=details&amp;id=24\">Hier</a></p><br />\n<p><strong>Buglist:</strong></p><br />\n&lt;ul&gt;<br />\n &lt;li&gt;<br />\n     Beim Hochladen von Dateien kann es bei &amp;hellip;<br />\n','yltf','1','0',NULL,'008.jpg','1',NULL,'2006-09-27 17:28:00','2025-02-25 14:00:24');
