INSERT INTO `blogs` VALUES ('5','1','207','2008-01-07 21:16:00','2','MCS 1.59 workin','1','<p>Wir sind am Arbeiten was MCS 1.59 angeht.<br /><br />\neine Komplette Hilfe, neue Administration und ein paar Gimmicks wie<br /><br />\nPrivate Messages kommen alle noch in dieses Release mit rein</p><br />\n<p>fieser Bug in der Welcome gefunden und gel&ouml;st</p><br />\n','<p>Wir sind am Arbeiten was MCS 1.59 angeht.<br /><br />\neine Komplette Hilfe, neue Administration und ein paar Gimmicks wie<br /><br />\nPrivate Messages kommen alle noch in dieses Release mit rein</p><br />\n<p>fieser Bug in der Welcome gefunden und gel&ouml;st</p><br />\n','ylpb','1','0',NULL,'008.jpg','1',NULL,'2008-01-07 20:16:00','2025-02-25 14:00:24');
