INSERT INTO `blogs` VALUES ('9','1','203','2008-02-17 10:56:00','3','Is schon irre was man so macht','1','<p>Rotten Psychos ist für mich eine der besten Zeiten gewesen die ich hatte.<br /><br />\nDamals war DSL noch Teuer und man freute sich über jedes 1on1<br /><br />\nnun ist DSL billig und man hat keins weils dann doch finanzell nicht hinhaut</p><br />\n','<p>Rotten Psychos ist für mich eine der besten Zeiten gewesen die ich hatte.<br /><br />\nDamals war DSL noch Teuer und man freute sich über jedes 1on1<br /><br />\nnun ist DSL billig und man hat keins weils dann doch finanzell nicht hinhaut</p><br />\n','yvfb','1','0',NULL,'008.jpg','1',NULL,'2008-02-17 09:56:00','2025-02-25 14:00:24');
INSERT INTO `blogs` VALUES ('10','1','202','2008-11-28 10:27:00','1','How Tough - Rotten-Psychos online','1','<p>Herzlichste Gr?sse aus Bim?hlen w?nscht euch euer Asario.<br /><br />\nh?re grad ma wieder Musik und denke mir, was geht bei euch so ab.<br /><br />\nZur Zeit feile ich an der Neuen &lt;a target=\"rotte\" href=\"http://www.rotten-psychos.de\"&gt;Rotten Psychos Seite&lt;/a&gt; und das RP-Forum ist fast fertig.<br /><br />\nDas Forum ist eine Eigenentwicklung auf MCS Basis.<br /><br />\nHat mich ne menge Zeit gekostet bis alles so funktionierte wie gedacht.<br /><br />\nAber ich habs geschafft die Fehler die sich versteckt hatten zu finden.</p><br />\n','<p>Herzlichste Gr?sse aus Bim?hlen w?nscht euch euer Asario.<br /><br />\nh?re grad ma wieder Musik und denke mir, was geht bei euch so ab.<br /><br />\nZur Zeit feile ich an der Neuen &lt;a target=\"rotte\" href=\"http://www.rotten-psychos.de\"&gt;Rotten Psychos Seite&lt;/a&gt; und das RP-Forum ist fast fertig.<br /><br />\nDas Forum …</p><br />\n','y2in','1','0',NULL,'008.jpg','1',NULL,'2008-11-28 09:27:00','2025-02-25 14:00:24');
