INSERT INTO `blogs` VALUES ('12','1','200','2010-01-12 16:09:00','2','MCS 1.61 workin','1','<p>Marble Content System ist in version 1.61 erschienen.<br /><br />\nNeue Navigation neues Rechtesystem und etliche Zugaben sind ins Release eingeflossen.</p><br />\n<p>weitere infos zu MCS und dem aktuellen Status auf &lt;a target=\"marbl\" href=\"http://www.marblefx.de\"&gt;www.marblefx.de&lt;/a&gt;</p><br />\n','<p>Marble Content System ist in version 1.61 erschienen.<br /><br />\nNeue Navigation neues Rechtesystem und etliche Zugaben sind ins Release eingeflossen.</p><br />\n<p>weitere infos zu MCS und dem aktuellen Status auf &lt;a target=\"marbl\" href=\"http://www.marblefx.de\"&gt;www.marblefx.de&lt;/a&gt;</p><br />\n','ypse','1','0',NULL,'008.jpg','1',NULL,'2010-01-12 15:09:00','2025-02-25 14:00:24');
INSERT INTO `blogs` VALUES ('13','1','199','2010-06-19 18:31:00','1','Happy Birthday Asario','1','<p>Herzlichen Gl&uuml;ckwunsch Lieber Asario zum 27. Geburtstag.<br /><br />\nDer Tag war sch&ouml;n und das Wetter ging auch in Ordnung.<br /><br />\nFreue mich schon auf den Sommer.<br /><br />\nHabe nette Sachen geschenk bekommen und demn&auml;chst lad ich noch 1-2 Fineliner-Bilder hoch.<br /><br />\nHabt Spass, in liebe euer Asario.</p><br />\n','<p>Herzlichen Gl&uuml;ckwunsch Lieber Asario zum 27. Geburtstag.<br /><br />\nDer Tag war sch&ouml;n und das Wetter ging auch in Ordnung.<br /><br />\nFreue mich schon auf den Sommer.<br /><br />\nHabe nette Sachen geschenk bekommen und demn&auml;chst lad ich noch 1-2 Fineliner-Bilder hoch.<br /><br />\nHabt Spass, in liebe euer Asario. …</p><br />\n','yu51','1','0',NULL,'008.jpg','1',NULL,'2010-06-19 16:31:00','2025-02-25 14:00:24');
