INSERT INTO `blogs` VALUES ('19','1','193','2011-07-29 14:30:00','2','MCS Update steht bevor....','1','<p>Also hier mal wieder ein paar News aus der Devlog Ecke.<br /><br />\nDie Entwicklung von MCS 1.64 ist angelaufen....<br /><br />\nGeplant sind einige nette Features zwecks Private Messaging.<br /><br />\nUnter anderem soll ein komplettes Einstellungstool das Private Messaging noch einfacher machen.<br /><br />\nweitere Infos demn&auml;chst Hier...</p><br />\n','<p>Also hier mal wieder ein paar News aus der Devlog Ecke.<br /><br />\nDie Entwicklung von MCS 1.64 ist angelaufen....<br /><br />\nGeplant sind einige nette Features zwecks Private Messaging.<br /><br />\nUnter anderem soll ein komplettes Einstellungstool das Private Messaging noch einfacher machen.<br /><br />\nweitere Infos demn&auml;chst Hier... …</p><br />\n','ykf1','1','0',NULL,'008.jpg','1',NULL,'2011-07-29 12:30:00','2025-02-25 14:00:24');
