INSERT INTO `blogs` VALUES ('53','1','159','2015-03-20 16:51:00','0','Asario\'s Geschichte Part I','1','<p>Alles fing mit einem verkorksten 16. Geburtstag an.<br /><br />\nIch fuhr mit dem Rad durch die Gegend um mich abzureagieren und da traf ich sie wieder.<br /><br />\nEs waren die Punks vom See mit Ihren Hunden.<br /><br />\nIch spielte mit den Hunden und kam ins GesprÃƒÂ¤ch-<br /><br />\nWir redeten ÃƒÂ¼ber meinen Geburtstag und Sie fragten mich ob ich nicht mit in Ihre Kneipe kommen wÃƒÂ¼rde.<br /><br />\nIch sagte zu. Von da an war ich ÃƒÂ¶fter in der Kneipe. Es waren verstÃƒÂ¤ndnisvolle Menschen die vÃƒÂ¶llig natÃƒÂ¼rlich und nett waren. Ich fÃƒÂ¼hlte mich geborgen bei Ihnen.</p><br />\n<p>Nicht so wie bei meinen Eltern, wo nur Ehe-Krach und Scheidungsstreitigkeiten an der Tagesordnung waren.<br /><br />\nWenn ein Mensch Geborgenheit sucht und nichts ausser zerrÃƒÂ¼tteter VerhÃƒÂ¤ltnisse bekommt sucht man sich immer einen Ruhepol.<br /><br />\nDen hatte ich in dieser besagten Kneipe gefunden. Viele Hunde, nette Menschen und Party Party Party war das was ich da hatte.</p><br />\n<p>Die Partys waren eine gute MÃƒÂ¶glichkeit mich abzulenken. Ich trank ein Paar Bier und schon ging es mir viel Besser.<br /><br />\nZwar war das GefÃƒÂ¼hl nur fÃƒÂ¼r einen Moment vorhanden aber ich hatte meinen SpaÃƒÅ¸.</p><br />\n<p>Meine Leistungen in der Schule gingen rapide Bergab. Ich hatte einfach keine Lust es meinen Eltern Recht zu machen und in der Schule aufzupassen.<br /><br />\nIch entwickelte mich immer mehr von einem guten SchÃƒÂ¼ler zu einen Klassenclown.<br /><br />\nWIeso sollte ich meinem Traum vom Meeresbiologen denn weiter TrÃƒÂ¤umen wenn meine Eltern es nicht mal schaffen zusammenzuhalten ?</p><br />\n<p>Ich war frustriert und Lustlos von all dem ganzen Zeug.<br /><br />\nNur meine Punkerfreunde waren fÃƒÂ¼r mich da und machten mir Mut das irgendwann Licht am Ende des Tunnels sei.</p><br />\n<p>Ich hatte eine Zweite Familie gefunden.</p><br />\n<p>to be continued</p><br />\n','<p>Alles fing mit einem verkorksten 16. Geburtstag an.<br /><br />\nIch fuhr mit dem Rad durch die Gegend um mich abzureagieren und da traf ich sie wieder.<br /><br />\nEs waren die Punks vom See mit Ihren Hunden.<br /><br />\nIch spielte mit den Hunden und kam ins GesprÃƒÂ¤ch-<br /><br />\nWir redeten ÃƒÂ¼ber meinen Geburtstag und Sie fragten mich ob ich nicht mit …</p><br />\n','yjwu','2','0',NULL,'008.jpg','1',NULL,'2015-03-20 15:51:00','2025-02-25 14:00:24');
