INSERT INTO `blogs` VALUES ('61','1','151','2015-09-06 15:29:00','2','MCS v. 1.85 ist eingetroffen....','1','<p>Mal wieder wurde MCS erneuert.<br /><br />\nDazu gekommen sind einige kosmetische Eingriffe vorgenommen worden.<br /><br />\nEinige Formularelemente wurden mit Material Design aktualisiert.<br /><br />\nDazu kommen noch etliche Bugfixes in mehreren Komponenten.</p><br />\n<p>Hinzugekommen sind ein Datei-Synchronisations-Script um schneller neue Dateien zum Hochladen in die Update Ordner zu schieben.</p><br />\n<p>Au&szlig;erdem ist ein interner Chat entstanden.</p><br />\n<p>w&uuml;nsche viel Spa&szlig; mit MCS v. 1.85 ;)<br /><br />\nPS.: Momentan arbeite ich an der Integration von JQuery UI Elementen in das Admin Center.<br /><br />\nsee you soon, Paule aka Asario</p><br />\n','<p>Mal wieder wurde MCS erneuert.<br /><br />\nDazu gekommen sind einige kosmetische Eingriffe vorgenommen worden.<br /><br />\nEinige Formularelemente wurden mit Material Design aktualisiert.<br /><br />\nDazu kommen noch etliche Bugfixes in mehreren Komponenten.</p><br />\n<p>Hinzugekommen sind ein Datei-Synchronisations-Script um schneller neue Dateien …</p><br />\n','ym1n','1','0',NULL,'008.jpg','1',NULL,'2015-09-06 13:29:00','2025-02-25 14:00:24');
