INSERT INTO `blogs` VALUES ('63','1','149','2015-10-04 16:03:00','2','Neuerungen dank JQuery UI','1','<p>JQuery UI ist fast komplett integriert und ich habe kaum noch sachen zu machen... Habe jetzt alle Tabs auf den Seiten durch JQuery UI tabs ersetzt.</p><br />\n<p>Ist irgendwie irre was man so mach wenn man viel Zeit hat. War ein ganz sch&ouml;ner Krampf die Tabs einzubauen.<br /><br />\nIch musste alles was auf einzelnen extra Seiten war auf eine Seite reduzieren und die Verlinkung anpassen.</p><br />\n<p>Aber alles in allem hat es sich gelohnt. Sieht Jetzt Stylischer aus und geht alles sehr viel schneller.<br /><br />\nHab nat&uuml;rlich beim proggen etliche Bugs verursacht die ich m&uuml;hsam finden und beseitigen musste.</p><br />\n<p>Ein nettes Schmankerl ist auch die neue Shortstories Seite.</p><br />\n<p>aber jetzt m&uuml;sste eigentlich alles funken. wenn euch noch was auff&auml;llt schreibt mir ne PM oder mailt mir einfach &uuml;ber das Mailformular.</p><br />\n<p>Ach ja, Die Hilfe Seite hab ich komplett neu geschrieben und dabei ca. 80 Zeilen Code eingespart. Klingt nicht nach viel aber bei einem Vergleichsweise kleinem Script ist das schon ne Menge.</p><br />\n<p>PS: In den Privaten Nachrichten sind Smilies mit dabei.</p><br />\n<p>Bis Bald Asario.</p><br />\n','<p>JQuery UI ist fast komplett integriert und ich habe kaum noch sachen zu machen... Habe jetzt alle Tabs auf den Seiten durch JQuery UI tabs ersetzt.</p><br />\n<p>Ist irgendwie irre was man so mach wenn man viel Zeit hat. War ein ganz sch&ouml;ner Krampf die Tabs einzubauen.<br /><br />\nIch musste alles was auf einzelnen extra Seiten war auf …</p><br />\n','y5hp','1','0',NULL,'008.jpg','1',NULL,'2015-10-04 14:03:00','2025-02-25 14:00:24');
