INSERT INTO `blogs` VALUES ('67','1','145','2015-11-24 17:37:00','3','Meine Karriere zum freiwilligen Webdesigner und die Zunkunft...','1','<p>Alles fing im Informatikunterricht in der 9./10. Klasse an.<br /><br />\nWir lernten das Erstellen von Websites mit Microsoft Frontpage.<br /><br />\nIch war sofort begeistert wie einfach man Websites erstellen kann.<br /><br />\nIch erstellte einige Websites mit MS Frontpage und kam dann durch einen Kumpel zu PHP.<br /><br />\nPHP ist eine einfach zu erlernende Scriptsprache die meine Ideen aufsog wie ein nasser Schwamm.</p><br />\n<p>Nach einigen Jahren Programmiererfahrung entstand MCS, mein noch heute im Einsatz befindliches System, das <strong>Marble Content System</strong><br /><br />\nEine Vorlagen Engine sowie eine umfangreiche Administration entstanden in den darauffolgenden Jahren.<br /><br />\nMittlerweile ist alles vom Portal bis zur Web-Visitenkarte machbar.<br /><br />\nIch integrierte etliches n&uuml;tzliches aus meiner C\'t und bin immer noch am Arbeiten, neue Module zu erfinden bzw. alte zu verbessern</p><br />\n<p>Im Admin Center geht es los. Inhalte Einpflegen, Tabelleneinstellungen, Vorlagen Einstellungen, Benutzerprofile, Benutzerinhalte, Benutzergruppen und Rechte,<br /><br />\nNewsletter, Kontakte, Kalender, Private Nachrichten uvm.</p><br />\n<p>Momentan habe ich 3 Javascript Frameworks installiert, die Entweder aufh&uuml;bschen oder Funktionen nachr&uuml;sten.<br /><br />\nJQuery UI, Foundation, Material Framework sind bei mir auf der ein oder anderen MCS-Seite installiert.</p><br />\n<p>Momentan l&auml;uft MCS auf 8 Webseiten in meinem Webspace.</p><br />\n<p>Viele fragen sich, warum das Rad neu erfinden? Ich meine Wordpress, Typo3 oder Drupal k&ouml;nnen doch auch alles.<br /><br />\nDoch selbst ein &auml;lteres Mambo hat 60% Mehr Code als MCS<br /><br />\nEngines wie Smarty die mal eben 6000 Zeilen Code fressen wollte ich nicht integrieren.<br /><br />\nmeine Vorlagen Engine hat mit 474 Zeilen weniger Gewicht als Hochgez&uuml;chtete CMS\'es und ist dennoch funktional.</p><br />\n<p>Der Vorteil an MCS ist dass man die HTML Vorlagen mit einem Wysiwyg Editor komplett erstellen kann weil sie reines HTML sind.<br /><br />\nAngereichert mit in PHP geschriebenen Modulen und Funktionen sind sie hochdynamisch und schnell.<br /><br />\nWollt Ihr/ Willst du schon immer eine eigene Website haben wo du dich &uuml;ber dein Hobby oder dein Lieblingsthema auslassen willst so schreib mir doch &uuml;ber das <a href=\"kontakt\">Kontaktformular</a> falls du eine interessante Idee f&uuml;r eine Homepage hast. Ich freue mich &uuml;ber jede Anregung oder Idee.</p><br />\n<p>Forum, Chat, Shoutbox, Kommentare, G&auml;steb&uuml;cher sowie Bildergalerien, Texte, Fotos, Suchfunktion, RSS Stream, Smartphone Unterst&uuml;tzung uvm, wurden bereits Entwickelt und in MCS integriert. Wenn dir auch f&uuml;r meine Seite eine Idee einf&auml;llt schreib mir &uuml;ber das <a href=\"kontakt\">Kontakformular</a></p><br />\n<p>MCS is ready to Launch.</p><br />\n','<p>Alles fing im Informatikunterricht in der 9./10. Klasse an.<br /><br />\nWir lernten das Erstellen von Websites mit Microsoft Frontpage.<br /><br />\nIch war sofort begeistert wie einfach man Websites erstellen kann.<br /><br />\nIch erstellte einige Websites mit MS Frontpage und kam dann durch einen Kumpel zu PHP.<br /><br />\nPHP ist eine einfach zu …</p><br />\n','yhlm','2','0',NULL,'008.jpg','1',NULL,'2015-11-24 16:37:00','2025-02-25 14:00:24');
INSERT INTO `blogs` VALUES ('68','1','144','2015-12-18 18:17:00','1','Neue Galerie und einige nette Details','1','<p>Habe eine neue Galerie mit Zentangles erstellt.<br /><br />\nDa findet Ihr meine Fortschritte beim Tanglen.<br /><br />\nAuÃƒÅ¸erdem habe ich im Dokumentenfooter Links zu Kontakt,Datenschutz und Impressum integriert.<br /><br />\nUm dem Datenschutz nachzukommen habe ich Piwik so eingestellt das Ip Adressen nur gekÃƒÂ¼rzt aufgezeichnet werden.<br /><br />\nPiwik ist ein Statistiktool zum Auswerten der Besuche auf dem Server.<br /><br />\nIhr kÃƒÂ¶nnt jederzeit ÃƒÂ¼ber die fx_lxk(index.php?page=datenschutz|||Datenschutz) Einstellungen das Tracking deaktivieren.<br /><br />\nDie Statistischen Daten dienen der Verbesserung des Angebotes und sind Indikatoren fÃƒÂ¼r BesucherstrÃƒÂ¶me.<br /><br />\nWÃƒÂ¼nsche viel SpaÃƒÅ¸ mit meinen Seiten, In Liebe, Asario</p><br />\n','<p>Habe eine neue Galerie mit Zentangles erstellt.<br /><br />\nDa findet Ihr meine Fortschritte beim Tanglen.<br /><br />\nAuÃƒÅ¸erdem habe ich im Dokumentenfooter Links zu Kontakt,Datenschutz und Impressum integriert.<br /><br />\nUm dem Datenschutz nachzukommen habe ich Piwik so eingestellt das Ip Adressen nur gekÃƒÂ¼rzt aufgezeichnet werden.  …</p><br />\n','yusr','1','0',NULL,'daimkon.jpg','1',NULL,'2015-12-18 17:17:00','2025-02-25 14:00:24');
INSERT INTO `blogs` VALUES ('69','1','143','2016-01-03 16:15:00','1','Happy New Year','1','<p>Ich wÃƒÂ¼nsche allen Besuchern gut reingerutscht zu sein.<br /><br />\nIch hoffe Ihr habt nicht zu viel Zugenommen ÃƒÂ¼ber die Feiertage und seit gut reingerutscht<br /><br />\nNatÃƒÂ¼rlich hoffen wir das wir alle Gesund bleiben,<br /><br />\nund Erfolg im Beruf haben sowie das dieses ein glÃƒÂ¼ckliches Jahr wird</p><br />\n','<p>Ich wÃƒÂ¼nsche allen Besuchern gut reingerutscht zu sein.<br /><br />\nIch hoffe Ihr habt nicht zu viel Zugenommen ÃƒÂ¼ber die Feiertage und seit gut reingerutscht<br /><br />\nNatÃƒÂ¼rlich hoffen wir das wir alle Gesund bleiben,<br /><br />\nund Erfolg im Beruf haben sowie das dieses ein glÃƒÂ¼ckliches Jahr wird</p><br />\n','yl6i','1','0',NULL,'sylv_2015_2016.jpg','1',NULL,'2016-01-03 15:15:00','2025-02-25 14:00:24');
