INSERT INTO `blogs` VALUES ('81','1','131','2016-10-08 16:07:00','2','Neuerungen unter der Haube','1','<p>Mal wieder habe ich geschraubt und gemacht um MCS noch besser zu machen.<br /><br />\nUnter der Haube habe ich eine Synchronisationsumgebung gebaut um noch einfacher neue Inhalte zu publizieren.<br /><br />\nWenn ich also bei mir zu Hause Dateien oder Datenbankinhalte verÃƒÂ¤ndere bzw Erstelle so synchronisiert MCS alle Inhalte auf meinen Webspace.<br /><br />\nSomit muss ich mich nicht mit Datenbank Dumps rumÃƒÂ¤rgern und habe alle Seiten immer aktuell. Momentan schraube ich noch am RSS-Feed, der irgendwie noch nicht mit dem Sync-Client kompatibel scheint.<br /><br />\nAber gut ding will Weile haben, oder wie man auch sagt: Was lange Wert, wird endlich gut.<br /><br />\nIn diesem Sinne, Have Fun Folks.</p><br />\n','<p>Mal wieder habe ich geschraubt und gemacht um MCS noch besser zu machen.<br /><br />\nUnter der Haube habe ich eine Synchronisationsumgebung gebaut um noch einfacher neue Inhalte zu publizieren.<br /><br />\nWenn ich also bei mir zu Hause Dateien oder Datenbankinhalte verÃƒÂ¤ndere bzw Erstelle so synchronisiert MCS alle Inhalte auf meinen …</p><br />\n','y1cm','1','0',NULL,'17new_noname.jpg','1',NULL,'2016-10-08 14:07:00','2025-02-25 14:00:24');
