INSERT INTO `blogs` VALUES ('135','1','76','2019-05-27 07:16:00','1','Besuch bei meinem kleinem Neffen','1','<p>Ich habe letztes Wochenende zum ersten mal meinen Neffen im Arm halten k&ouml;nnen.<br /><br />\nEcht s&uuml;&szlig; der kleine Racker. Alfred, so hei&szlig;t er ist ein echt s&uuml;&szlig;es Baby.<br /><br />\nMit einem Kampfgewicht von 4290 g und einer K&ouml;rperl&auml;nge von 56 cm war das ein ganz sch&ouml;ner Brocken. Aber er ist gesund und munter, was die Hauptsache ist.</p><br />\n<p>Au&szlig;erdem habe ich ein Wallpaper mit Alfred versch&ouml;nert.<br /><br />\nUnd ich habe die Pr&auml;mien ver&auml;ndert. Viele Artworks sind jetzt mit noch weniger Punkten zu haben. Viel Spa&szlig; beim posten &amp; bewerten.</p><br />\n','<p>Ich habe letztes Wochenende zum ersten mal meinen Neffen im Arm halten k&ouml;nnen.<br /><br />\nEcht s&uuml;&szlig; der kleine Racker. Alfred, so hei&szlig;t er ist ein echt s&uuml;&szlig;es Baby.<br /><br />\nMit einem Kampfgewicht von 4290 g und einer K&ouml;rperl&auml;nge von 56 cm war das ein ganz sch&ouml;ner Brocken. Aber er ist gesund und munter, was die Hauptsache ist.  …</p><br />\n','y0lx','1','0',NULL,'100new_noname.jpg','1',NULL,'2019-05-27 05:16:00','2025-02-25 14:00:24');
