INSERT INTO `blogs` VALUES ('142','1','69','2019-12-28 15:54:00','1','Gut reingerutscht?','1','<p>Auch dieses mal lassen wir ein Jahr voller Erlebnissen und Ereignissen hinter uns.<br /><br />\nLiebe, Job und Gesundheit sollen in diesem Jahr besser werden sagte mir der Experte Prof. Dr. As-Ario k&uuml;rzlich in einem Interview zum neuen Jahr.</p><br />\n<p>Viel Gl&uuml;ck, Leute.</p><br />\n','<p>Auch dieses mal lassen wir ein Jahr voller Erlebnissen und Ereignissen hinter uns.<br /><br />\nLiebe, Job und Gesundheit sollen in diesem Jahr besser werden sagte mir der Experte Prof. Dr. As-Ario k&uuml;rzlich in einem Interview zum neuen Jahr.</p><br />\n<p>Viel Gl&uuml;ck, Leute.</p><br />\n','yc1f','1','0',NULL,'111new_noname.jpg','1',NULL,'2019-12-28 14:54:00','2025-02-25 14:00:24');
