INSERT INTO `didyouknow` VALUES ('24','1','98','1',' dass die Zeit schneller vergeht wenn einem etwas Spaß macht','Wenn wir Spaß an einer Sache haben kommt einem die Zeit kürzer vor.  \nMan nehme 2 Gruppen, eine Spielt Billiard mit Frauen in Bikini und eine Gruppe schält Kartoffeln. Gruppe 1 dachte das sie eine viertel Stunde gespielt hat, während die Andere Gruppe glaubte eine Dreviertelstunde zu schälen. Beide Gruppen waren 30 Minuten beschäftigt.  \nErgo, wenn eine Sache Spaß macht vergeht die Zeit schneller.+\n','1','2018-05-17 20:21:26','2018-05-17 17:28:14');
