INSERT INTO `images` VALUES ('10','1','341','10','Bahnof Potsdamer Platz bei Nacht','Bahnof Potsdamer Platz bei Nacht','empty','2006-09-27 19:39:01','1','39','1680','2240','1159315800','<p>Gestern Abend ich mit Kamera in Berlin und musste auf nen Zug warten,  <br /><br />\nda fiel mir dieses Ausergewöhnliche Bild ins Auge, musst ich gleich ma Fotofiern.</p>\n','<p>Gestern Abend ich mit Kamera in Berlin und musste auf nen Zug warten,  <br /><br />\nda fiel mir dieses Ausergewöhnliche Bild ins Auge, musst ich gleich ma Fotofiern.</p>\n','3','','Potsdamer-Platz.jpg','','0','1','1','0','1');
