INSERT INTO `images` VALUES ('329','1','82','2','El Novum','EL Novum','sold','2021-12-25 19:39:01','3','17','7680','3376','1659105444','<p>Neun schmale, vertikale Leinwände mit Mustern in Orange, Rot und Schwarz. Die abstrakten, tribalartigen Muster bestehen aus geometrischen Formen, die sich über die einzelnen Leinwände hinweg fortsetzen.</p>\n','<p>Nine narrow, vertical canvases with patterns in orange, red and black. The abstract, tribal-like patterns consist of geometric shapes that continue across the individual canvases.</p>\n','7','','El_Novum_Finiished.jpg','9x 80cm x 20cm','525.25','1','1','1','1');
