INSERT INTO `images` VALUES ('333','1','80','6','Alfies Traktor','Alfies Tractor','givenaway','2023-11-08 19:39:01','2','14','603','596','1692887867','<p>Pünktlich zu Weihnachten habe ich meinem Neffen ein Geschenk gemacht.<br /><br />\nDa er voll auf Träcker steht habe ich dieses Bild auf Leinwand verewigt.</p><p>Es ist mit Filzern gemalt.</p>\n','<p>Just in time for Christmas, I made a present for my nephew.<br /><br />\nSince he is really loving Tractors, I immortalised this picture on canvas.</p><p>It is painted with felt-tip-pens.</p>\n','11',NULL,'tractor_cut.jpg',NULL,'0','1','1','0','1');
