INSERT INTO `images` VALUES ('337','2','77','1','Dragonbird 3D','Dragonbird 3D','forsale','2022-06-18 19:39:01','5','38','4000','3000','1667572762','<p>Mein erstes gedrucktes Relief mit meinem Renkforce Pro3.  <br /><br />\nDer 3D-Drucker meines Vertrauens ermöglichte mir dieses Kunstwerk zu erschaffen.</p>\n','<p>My first printed relief with my Renkforce Pro3.  <br /><br />\nThe 3D printer I trust enabled me to create this work of art.</p>\n','7','','dragonbird 3D.jpg','','25','1','1','1','1');
