INSERT INTO `images` VALUES ('347','1','69','1','Caustic Treble 3D','Caustic Treble 3D','forsale','2023-01-11 19:39:01','5','38','3322','2010','1673451790','<p>Das Design ist echt cool, wie ein modernes Kunstwerk aus dem 3D-Drucker. Die Linien und Formen sind richtig spannend, fast futuristisch. In Weiß wirkt das Ganze total clean und einzigartig - ein echter Hingucker!</p><br />','<p>The design is really cool, like a modern work of art from a 3D printer. The lines and shapes are really exciting, almost futuristic. In white, the whole thing looks totally clean and unique - a real eye-catcher!</p><br />','7','','caustic-treble 3D.jpg','','25','1','1','1','1');
