INSERT INTO `newsletter` VALUES ('3','1','33','1','AB Newsletter 01','Asarios Blog, mein erster Newsletter','2025-10-12 14:28:24','2025-10-12 14:28:24','Hallo [nick],  <br />\nWie du vielleicht siehst ist die Newsletter Funktion eingebaut worden.  <br />\nHiermit kÃ¶nnen Administratoren Newsletter an unsere Mitglieder versenden.  <br />\n  <br />\nIch habe mir erlaubt, die Kommentar-Funktionen weiter zu Ã¶ffnen so das unerwÃ¼nschte Werbung am Filter abprallt.  <br />\n  <br />\nSomit werden die Kommentare automatisch verÃ¶ffentlicht falls keine Ungereimtheiten entdeckt werden.  <br />\n  <br />\nAuÃŸerdem mÃ¶chte ich Hinweisen das Sonntag den 06.09.2015 wieder in Ricklingen das Jahresfest stattfindet. Im Maleratelier sind Bilder und Lampen ausgestellt, vielleicht passt ja das eine oder andere StÃ¼ck in eure \"Butze\". Ich wÃ¼rde mich freuen wenn Ihr mal nen Blick ins Maleratelier werft.  <br />\n  <br />\nDiese Nachricht erscheint nur wenn der Newsletter aktiviert wurde.  <br />\nFalls du diesen Newsletter nicht mehr empfangen willst, klick auf den Link am Ende der Nachricht.  <br />\n  <br />\nAlso na dann mal viel SpaÃŸ auf http://www.ab.marblefx.de','0','','');
