INSERT INTO `newsletter` VALUES ('39','1','11','1','summ2024','Neues Layout und Facebook Links','2024-06-13 14:52:30','2024-06-13 14:52:30','<b>Asarios Blog Newsletter</b>\r\n\r\n<b>Neues Layout in Blau</b>\r\n\r\nWir freuen uns, Ihnen unser neues, blaues Design vorstellen zu können! Das frische Farbschema verbessert die Lesbarkeit und schafft eine beruhigende Atmosphäre, die das Lesen unserer Inhalte noch angenehmer macht. Wir haben das Layout aktualisiert, um die Navigation zu erleichtern und sicherzustellen, dass Sie die gewünschten Informationen schneller finden. Schauen Sie vorbei und erleben Sie unser neues Design!\r\n\r\n<b>Facebook-Profil verlinken</b>\r\n\r\nWir möchten es Ihnen noch einfacher machen, sich mit uns und anderen Lesern zu vernetzen. Ab sofort können Sie in Ihren Profileinstellungen Ihren Facebook-Link hinzufügen. So können Sie Ihr Netzwerk erweitern und direkt über unsere Plattform mit der Community in Kontakt treten. Gehen Sie einfach zu Ihren Profileinstellungen und fügen Sie Ihren Facebook-Link hinzu, um loszulegen.\r\n\r\nIhr Asarios Blog Team\r\n','0','Pixn7fOvIrc6cOS25JCnZR9vOKxpaZkRKtg1UhDttfoTm5ZaL2O','');
INSERT INTO `newsletter` VALUES ('40','1','10','1','test008','Laravel Update Blog','2024-10-10 12:55:43','2024-10-10 12:55:43','Laravel kommt vorwÃ¤rts...\r\nHope u enjoy','3','Et1DFN0CujyW2LqgwPwEOI9uVVEFpCE0KE1GUiUoApWKjyI0FqK','');
INSERT INTO `newsletter` VALUES ('51','1','8','1','Asarios Blog Newsletter 11/25','Asarios Blog Newsletter 11/25','2025-10-29 16:05:31','2025-10-29 16:05:31','<h2>Asarios Blog Newsletter 11/25</h2><p><strong>Asarios Blog wurde komplett neu aufgesetzt – jetzt auf Basis von MCSL.</strong></p><p> Das neue Fundament bringt moderne Technologie, mehr Dynamik und eine spürbar schnellere Oberfläche.</p><p>Frameworks gibt es viele. Manche glänzen, manche stolpern. MCSL? Steht stabil. Laravel bildet das Rückgrat – stark, elegant, kein Firlefanz. Artisan macht den langweiligen Kram, Module lassen sich stapeln wie Lego, und Sicherheitslücken? Müssen draußen bleiben.</p><p>Vue.js kommt dann herein wie ein frischer Wind. Echtzeit-Updates, Drag-and-Drop, Inline-Bearbeitung – alles reagiert sofort. Keine Seite muss neu laden, keine Maus muss warten. Komponenten fügen sich zusammen, als hätten sie sich schon ewig gekannt.</p><p>MCSL ist nicht einfach ein CMS. Es ist ein Motor. Daten fließen in Echtzeit, APIs greifen ineinander, Oberflächen reagieren sofort. Modernes Web, dynamisch, clever – und bereit, Asarios Blog auf Touren zu bringen.</p><p>Kurz gesagt: Stabil, schnell, interaktiv – MCSL macht den Blog lebendig. Und ja, man merkt sofort, dass hier jemand dachte: „Geht besser. Geht moderner. Geht einfacher.“</p><p>mfg, Asario</p>','1','TrJMaeXTILZLdLMTFBFRBeWJDaWzAr.eg6Jez_7RfRULr6aH5ABnIgDpasdAu4Zp',NULL);
INSERT INTO `newsletter` VALUES ('52','1','7','1','Asarios Blog Newsletter 12/25','Asarios Blog Newsletter 12/25','2025-12-18 18:42:07','2025-12-18 18:42:07','<p data-start=\"35\" data-end=\"120\"><p><h2>Asarios Blog Newsletter 12/25</h2></p></p><p data-start=\"35\" data-end=\"120\">Der Dezember ist kalt, aber klar.<br data-start=\"68\" data-end=\"71\">Zeit, aufzuräumen. Zeit, Dinge richtig zu machen.</p><p data-start=\"122\" data-end=\"415\">Wir haben begonnen, genauer hinzusehen.<br data-start=\"161\" data-end=\"164\">\nMit dem neuen <strong data-start=\"178\" data-end=\"192\">Countpixel</strong> wird jeder Besuch gezählt, ohne Lärm, ohne falsche Versprechen. Es misst nur, was wirklich passiert. Seiten werden aufgerufen, Leser kommen, Leser gehen. Die Zahlen sind da. Nüchtern. Verlässlich. Genau so sollen sie sein.</p><p data-start=\"417\" data-end=\"671\"><br></p><p data-start=\"417\" data-end=\"671\">Das <strong data-start=\"421\" data-end=\"438\">Cookie-Banner</strong> ist neu.<br data-start=\"447\" data-end=\"450\">Es drängt sich nicht auf. Es schreit nicht.<br data-start=\"493\" data-end=\"496\">Es sagt, was Sache ist, und wartet auf eine Entscheidung.<br data-start=\"553\" data-end=\"556\">Akzeptieren oder ablehnen. Beides ist in Ordnung.<br data-start=\"605\" data-end=\"608\">Der Leser behält die Kontrolle, und das System respektiert das.</p>\n<p data-start=\"673\" data-end=\"915\">Der Zugang zum Blog wurde vereinfacht.<br data-start=\"711\" data-end=\"714\"><strong data-start=\"714\" data-end=\"737\">Sign in with Google</strong> ist jetzt möglich.<br data-start=\"756\" data-end=\"759\">Kein neues Passwort, kein Formular zu viel.<br data-start=\"802\" data-end=\"805\">Ein Klick, und man ist da.<br data-start=\"831\" data-end=\"834\">Wer lesen will, liest. Wer schreiben will, schreibt.<br data-start=\"886\" data-end=\"889\">Der Rest wird weggelassen.</p>\n<p data-start=\"917\" data-end=\"1216\">Im Hintergrund arbeitet die <strong data-start=\"945\" data-end=\"974\">Datenbank-Synchronisation</strong>.\nSie vergleicht lokal und online, Zeile für Zeile, Spalte für Spalte.\nUnterschiede werden sichtbar gemacht.\nNichts wird blind überschrieben.\nErst sehen, dann entscheiden.\nSo bleibt die Ordnung erhalten, auch wenn sich etwas ändert.</p>\n<p data-start=\"1218\" data-end=\"1351\">Es sind keine lauten Neuerungen.<br data-start=\"1250\" data-end=\"1253\">Keine, die man anschreit.\nAber sie tragen.<br data-start=\"1297\" data-end=\"1300\">\nSie machen den Blog stabiler, ehrlicher, einfacher.</p><p data-start=\"1353\" data-end=\"1446\">Wir gehen mit weniger Ballast ins neue Jahr.\nDas System steht.<br data-start=\"1417\" data-end=\"1420\">\nDer Rest kommt von selbst.</p><p data-start=\"1353\" data-end=\"1446\"><br></p><p data-start=\"1353\" data-end=\"1446\"><a href=\"https://www.asario.de\" target=\"_blank\" rel=\"noopener noreferrer\">Visit www.asario.de</a></p>','1','asdaaeXTILZLdLMTFBFRBeWJDaWzAr.eg6Jez_7RfRULr6aH5ABnIgDpnvPAu4Zp',NULL);
INSERT INTO `newsletter` VALUES ('53','1','6','1','Asarios Blog Newsletter 12/25 2.0','Asarios Blog Newsletter 12/25','2025-12-18 18:49:42','2025-12-18 18:49:42','<p data-start=\"153\" data-end=\"239\"><h2>Asarios Blog Newsletter 12/25</h2></p><p data-start=\"153\" data-end=\"239\">Der Dezember ist kalt, aber klar.<br data-start=\"186\" data-end=\"189\">Zeit, Dinge sauber zu machen. Zeit, genau zu sein.</p>\n<p data-start=\"241\" data-end=\"504\">Wir zählen jetzt nur noch, was gezählt werden darf.<br data-start=\"292\" data-end=\"295\">Mit dem neuen <strong data-start=\"309\" data-end=\"323\">Countpixel</strong> wird <strong data-start=\"329\" data-end=\"385\">jeder Besuch erfasst – aber nur, wenn er erlaubt ist</strong>.<br data-start=\"386\" data-end=\"389\">Kein verstecktes Tracking. Kein Zwang.<br data-start=\"427\" data-end=\"430\">Ist das Countpixel aktiviert, wird gezählt.<br data-start=\"473\" data-end=\"476\">Ist es aus, bleibt es still.</p>\n<p data-start=\"506\" data-end=\"704\">Das <strong data-start=\"510\" data-end=\"527\">Cookie-Banner</strong> ist neu.<br data-start=\"536\" data-end=\"539\">Es erklärt sich knapp und bleibt höflich.<br data-start=\"580\" data-end=\"583\">Keine Tricks, keine Umwege.<br data-start=\"610\" data-end=\"613\">Der Besucher entscheidet selbst, ob gemessen wird oder nicht.<br data-start=\"674\" data-end=\"677\">Das System hält sich daran.</p>\n<p data-start=\"706\" data-end=\"921\">Der Zugang zum Blog ist einfacher geworden.<br data-start=\"749\" data-end=\"752\">Mit <strong data-start=\"756\" data-end=\"779\">Sign in with Google</strong> geht es schneller.<br data-start=\"798\" data-end=\"801\">Ein Klick reicht.<br data-start=\"818\" data-end=\"821\">Kein neues Passwort. Kein unnötiger Schritt.<br data-start=\"865\" data-end=\"868\">Wer rein will, kommt rein. Wer nicht, bleibt draußen.</p>\n<p data-start=\"923\" data-end=\"1157\">Im Hintergrund arbeitet die <strong data-start=\"951\" data-end=\"980\">Datenbank-Synchronisation</strong>.<br data-start=\"981\" data-end=\"984\">Lokal und online werden verglichen, sachlich und genau.<br data-start=\"1039\" data-end=\"1042\">Unterschiede werden markiert, nicht versteckt.<br data-start=\"1088\" data-end=\"1091\">Nichts wird automatisch überschrieben.<br data-start=\"1129\" data-end=\"1132\">Erst sehen, dann handeln.</p>\n<p data-start=\"1159\" data-end=\"1279\">Es sind keine großen Gesten.<br data-start=\"1187\" data-end=\"1190\">Aber es sind ehrliche Änderungen.<br data-start=\"1223\" data-end=\"1226\">Sie machen den Blog ruhiger. Stabiler. Verlässlicher.</p><p data-start=\"1281\" data-end=\"1362\">Wir gehen geordnet ins neue Jahr.<br data-start=\"1314\" data-end=\"1317\">\nDer Code ist sauber.<br data-start=\"1337\" data-end=\"1340\">Der Rest darf wachsen.</p><p data-start=\"1281\" data-end=\"1362\"><br></p><p data-start=\"1281\" data-end=\"1362\">Visit <a href=\"https://www.asario.de\" target=\"_blank\" rel=\"noopener noreferrer\">www.asario.de</a></p>','1','TrJMaeXTILZLdLsadsdBeWJDaWzAr.eg6Jez_7RfRULr6aH5ABnIgDpnvPAu4Zp',NULL);
INSERT INTO `newsletter` VALUES ('56','1','3','1','Asarios Blog Newsletter 01/26','Asarios Blog Newsletter 01/26','2026-01-25 13:59:30','2026-01-25 13:59:30','Der Absturz ist vorbei.\nMCSL steht wieder auf.\nich haben ihn gefixt, genau dort, wo er uns getroffen hat.\nNicht mit Worten, sondern mit Arbeit.\n\nDie Seiten blättern wieder. Die Pagination funktioniert wieder.\nDu kannst durch Beiträge und Listen gehen, ohne dass etwas hängen bleibt oder springt.\nDas ist so, wie es sein soll.\n\nDer Spinner.\nEr war dort, wo er nicht hingehört.\nBei Suchangaben tauchte er auf und blieb hängen.\nDas ist jetzt vorbei.\nDer Spinner erscheint nur noch, wenn er wirklich etwas zu tun hat.\nNicht mehr als Spielzeug. Nicht mehr als Störung.\n\nDie Newsletter-zu-PM-Funktionen wurden verbessert.\nSie arbeiten nun stabil und zuverlässig.\nDu kannst Newsletter direkt an deine Privaten Nachrichten senden lassen.\nOhne Stolpern. Ohne Fehler.\nSo, wie man es erwartet.\n\nUnd ich habe weitere Bugs beseitigt.\nKleine Fehler, die sich eingeschlichen hatten.\nich haben sie gefunden und aus dem Weg geräumt.\nEiner nach dem anderen.\nStill und gründlich.\n\nDanke, dass du MCSL nutzt.\nDanke, dass du dranbleibst.\nich mache weiter.\nich halte es am Laufen.\n\n— Dein Asario\n\nVisit <a href=\"https://www.asario.de.\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.asario.de.</a>','6',NULL,NULL);
INSERT INTO `newsletter` VALUES ('57','1','2','1','Asarios Blog Newsletter 01/26 v.2','Asarios Blog Newsletter 01/26','2026-01-25 19:04:59','2026-01-25 19:04:59','Der Absturz ist vorbei, ich hatte einen Server Crash.<br>MCSL steht wieder auf.\r\nich haben ihn gefixt, genau dort, wo er mich getroffen hat.\r\nNicht mit Worten, sondern mit Arbeit.\r\n\r\nDie Seiten blättern wieder. Die Pagination funktioniert wieder.\r\nDu kannst durch Beiträge und Listen gehen, ohne dass etwas hängen bleibt oder springt.\r\nDas ist so, wie es sein soll.\r\n\r\nDer Spinner.\r\nEr war dort, wo er nicht hingehört.\r\nBei Suchangaben tauchte er auf und blieb hängen.\r\nDas ist jetzt vorbei.\r\nDer Spinner erscheint nur noch, wenn er wirklich etwas zu tun hat.\r\nNicht mehr als Spielzeug. Nicht mehr als Störung.\r\n\r\nDie Newsletter-zu-PM-Funktionen wurden verbessert.\r\nSie arbeiten nun stabil und zuverlässig.\r\nDu kannst Newsletter direkt an deine Privaten Nachrichten senden lassen.\r\nOhne Stolpern. Ohne Fehler.\r\nSo, wie man es erwartet.\r\n\r\nUnd ich habe weitere Bugs beseitigt.\r\nKleine Fehler, die sich eingeschlichen hatten.\r\nich habe sie gefunden und aus dem Weg geräumt.\r\nEiner nach dem anderen.\r\nStill und gründlich.\r\n\r\nDanke, dass du MCSL nutzt.\r\nDanke, dass du dranbleibst.\r\nich mache weiter.\r\nich halte es am Laufen.\r\n\r\n— Dein Asario\r\n\r\nVisit <a href=\"https://www.asario.de.\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.asario.de.</a>','6',NULL,NULL);
INSERT INTO `newsletter` VALUES ('58','1','1','1','AB Newsletter 01/26','Asarios Blog Newsletter 01/26','2026-01-25 20:28:58','2026-01-25 20:28:58','<p>Der Absturz ist vorbei, ich hatte einen Server-Crash.</p><p>Doch MCSL steht wieder auf.</p><p>Ich habe ihn genau dort reaktiviert, wo er mich im Stich gelassen hat.</p><p>Nicht mit Worten, sondern mit Arbeit.</p><p><br></p><p>Die Seiten lassen sich wieder blättern. Die Pagination funktioniert wieder.</p><p>Du kannst wieder durch Beiträge und Listen gehen, ohne dass etwas hängen bleibt oder springt.</p><p>Es ist wieder so, wie es sein soll.</p><p><br></p><p>Der Loading Spinner.</p><p>Er war dort, wo er nicht hingehörte.</p><p>Bei Suchangaben tauchte er auf und blieb hängen.</p><p>Das ist jetzt vorbei.</p><p>Der Spinner erscheint nur noch, wenn er wirklich etwas zu tun hat.</p><p>Nicht mehr als Spielzeug. Nicht mehr als Störung.</p><p><br></p><p>Die Newsletter-zu-PM-Funktionen wurden verbessert.</p><p>Sie arbeiten nun stabil und zuverlässig.</p><p>Du kannst Newsletter direkt an deine privaten Nachrichten senden lassen.</p><p>Ohne Stolperfallen. Ohne Fehler.</p><p>So, wie man es erwartet.</p><p><br></p><p>Und ich habe weitere Bugs beseitigt.</p><p>Kleine Fehler, die sich eingeschlichen hatten, habe ich gefunden und beseitigt.</p><p>Ich habe sie gefunden und aus dem Weg geräumt.</p><p>Einer nach dem anderen.</p><p>Still und gründlich.</p><p><br></p><p>Danke, dass du MCSL nutzt.</p><p>Danke, dass du dranbleibst.</p><p>Ich mache weiter.</p><p>Ich halte es am Laufen.</p><p><br></p><p>– Dein Asario</p><p><br></p><p>Besuche https://www.asario.de.</p><p><br></p>','6',NULL,NULL);
