INSERT INTO `texts` VALUES ('9','1','3','Künstliche Intelligenz Bei Asario.de','<p></p><p>Bildgenerierende KIs öffnen Türen, von denen wir lange nicht wussten, dass sie da sind. Sie nehmen ein paar Worte, schlicht wie Kieselsteine in der Hand, und formen daraus Bilder, die größer wirken als das, was man hineingelegt hat. Sie tun es ohne Zittern, ohne Zweifel, nur mit der stillen Genauigkeit einer Maschine, die gelernt hat, die Welt auf ihre Weise zu sehen.</p><p><br /></p><p>Man gibt ihnen eine Beschreibung, ein Gefühl, einen Gedanken. Und sie antworten mit Farben, mit Licht, mit Formen, die manchmal fremd wirken und manchmal erstaunlich vertraut. In Kunst, im Design, im Marketing – überall dort, wo Menschen Bilder brauchen – sind diese neuen Werkzeuge angekommen wie ein frischer Wind, der keine Erlaubnis braucht.</p><p><br /></p><p>Die Bilder, die mit „AI“ markiert sind, wurden mit NightCafe Studio geschaffen. Manche wurden danach weiter verfeinert, wie man ein Messer nachschärft, obwohl es schon gut schneidet. Doch der erste Schlag, die erste Kontur, stammt von der Maschine.</p>','ai',NULL,'1','2024-10-21 09:55:17');
INSERT INTO `texts` VALUES ('12','1','4','Sie haben nicht die benötigten Rechte','<p>Diese Seite wurde gesperrt.<br /><br /><br /><br /><br />Wenden Sie sich an den Administrator falls Sie diese Funktion benötigen</p><p>Kontakt hier: <a href=\"http://www.marblefx.net/home/contacts\">http://www.marblefx.net/home/contacts</a></p><p></p>','no-rights',NULL,'1','2024-10-21 12:29:42');
INSERT INTO `texts` VALUES ('16','1','5','Kontakt','<div><strong>Wir freuen uns, von Ihnen zu hören!</strong><br /></div><div>Ob Fragen, Feedback oder ein konkretes Anliegen – Asario steht Ihnen jederzeit zur Verfügung.</div><div>Nutzen Sie gerne die untenstehenden Kontaktdaten oder senden Sie uns direkt eine Nachricht</div><div>über das Kontaktformular.</div>','ContactsHeader',NULL,'1','2025-08-10 11:16:51');
INSERT INTO `texts` VALUES ('17','1','6','Kontaktdaten','Paul Rieser<div>Dorfplatz 10</div><div>24576 Bimöhlen</div><div>Mobil: 0162/7716325</div><div>email: <a href=\"mailto:paul.rieser@marblefx.de\">paul.rieser%5Bat%5Dmarblefx.de</a></div>','ContactsInfos',NULL,'1','2025-08-10 11:34:24');
INSERT INTO `texts` VALUES ('18','1','0','Hol dir deine Lieblingsbilder mit MCSL Points!','Jede Aktivität zählt: Ob Kommentare, Newsletter, Bewertungen oder Shortpoems –<br /><br />sammle fleißig Punkte und tausche sie gegen exklusive Bilder ein.<br /><br />Mehr Punkte = mehr coole Prämien für deine Butze, oder zum verschenken','yfh7',NULL,'1','2025-12-26 13:04:19');
INSERT INTO `texts` VALUES ('20','1','2','Android CSV exportieren','Kontakte exportieren<br /><br />Öffnen Sie <a href=\"https://www.google.com/contacts/u/0/?cplus%3D0#contacts\">Google Kontakte.</a><br />Wählen Sie eine der folgenden Möglichkeiten aus:<div><br />Einzelner Kontakt: Klicken Sie das Kästchen neben dem Namen des Kontakts an.<br />Mehrere Kontakte: Klicken Sie die Kästchen neben den Kontakten an, die Sie exportieren möchten.<br />Alle Kontakte: Klicken Sie das Kästchen neben einem der Kontakte an und klicken Sie links oben auf Aktionen für Auswahl und dann Alle.<div><br />Klicken Sie rechts oben auf das Dreipunkt-Menü Dreipunkt-Menüund dann Exportieren.<br /><br /></div><div>Wählen Sie Google CSV aus, um Ihre Kontakte zu sichern.<br />Klicken Sie auf Exportieren, um die Datei zu speichern.<br /></div></div><div><br /></div><div>Dann die CSV hochladen, Kontakte auswählen und fertig</div>','ycrs','kontakte_help_android','1','2026-02-21 09:14:34');
INSERT INTO `texts` VALUES ('21','1','1','CSV Export IOS','lade dir diese App herunter:<br />https://apps.apple.com/de/app/kontakte-export-pro-csv-excel/id1356211837<br /><div><br /></div><div>Schritt-für-Schritt Anleitung:<br />App öffnen: Starten Sie Kontakte Export Pro: CSV Excel auf Ihrem iOS-Gerät.<br /><br /></div><div>Berechtigungen: Erlauben Sie der App den Zugriff auf Ihre Kontakte, wenn Sie dazu aufgefordert werden.<br /><br /></div><div>Export-Funktion: Wählen Sie die Option zum Exportieren (meist ein \"Export\" oder Pfeil-Symbol).<br /><br /></div><div>Format wählen: Wählen Sie CSV als Zielformat.<br />Optionen: Passen Sie ggf. die Felder an, die exportiert werden sollen.<br /><br /></div><div>Exportieren &amp; Speichern: Klicken Sie auf \"Exportieren\". Die App bietet dann an, die Datei über die Dateien-App zu speichern, per E-Mail zu senden oder in anderen Apps (z.B. Numbers, Excel) zu öffnen. <br /><br /></div><div><br /></div><div>Dann die runtergeladene CSV hochladen, Kontakte auswählen und fertig</div>','yd5i','kontakte_help_ios','1','2026-02-21 09:29:28');
